// =============================================================================
// EF Core 9 – Cosmos DB Breaking Changes & Required Fixes
// Apply these patterns to your Cosmos DB project.
// =============================================================================

using Microsoft.EntityFrameworkCore;

// -----------------------------------------------------------------------------
// BREAKING CHANGE 1: Default discriminator property renamed "$type"
//
// EF Core 9 changed the default Cosmos discriminator property from
// "Discriminator" to "$type". Existing documents still store "Discriminator",
// so queries against them will silently return no results unless you
// explicitly restore the old property name.
// -----------------------------------------------------------------------------

class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Fix: keep the legacy property name so existing documents are found
        modelBuilder.Entity<Product>()
            .HasDiscriminator<string>("Discriminator")
            .HasValue<Product>("Product");
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
}

// -----------------------------------------------------------------------------
// BREAKING CHANGE 2: Synchronous Cosmos DB I/O now throws
//
// The Azure Cosmos SDK removed synchronous I/O support.  EF Core 9 surfaces
// this as an InvalidOperationException when you call ToList(), First(),
// Single(), Count(), etc.  You must switch to their async counterparts.
// -----------------------------------------------------------------------------

class ProductService
{
    private readonly CosmosDbContext _db;
    public ProductService(CosmosDbContext db) => _db = db;

    // ❌ BEFORE (throws in EF Core 9):
    // List<Product> GetAll() => _db.Products.ToList();
    // Product GetFirst()     => _db.Products.First();
    // int GetCount()         => _db.Products.Count();

    // ✅ AFTER – use async equivalents:
    async Task<List<Product>> GetAllAsync() =>
        await _db.Products.ToListAsync();

    async Task<Product> GetFirstAsync() =>
        await _db.Products.FirstAsync();

    async Task<int> GetCountAsync() =>
        await _db.Products.CountAsync();
}

